    #[test]
    fn test_concurrent_vec_concurrent_read_write() {
        let vec = ConcurrentVec::new();

        // Pre-populate
        for i in 0..10 {
            vec.push(i).unwrap();
        }

        let mut handles = Vec::new();

        // Writers that modify existing elements
        for _ in 0..4 {
            let vec_clone = vec.clone();
            let handle = thread::spawn(move || {
                for idx in 0..10 {
                    if let Some(cell) = vec_clone.get(idx) {
                        if let Ok(mut guard) = cell.write() {
                            *guard.get_mut() += 1;
                        }
                    }
                }
            });
            handles.push(handle);
        }

        // Readers
        for _ in 0..4 {
            let vec_clone = vec.clone();
            let handle = thread::spawn(move || {
                for idx in 0..10 {
                    if let Some(cell) = vec_clone.get(idx) {
                        if let Ok(guard) = cell.read() {
                            let _val = *guard.get();
                        }
                    }
                }
            });
            handles.push(handle);
        }

        for handle in handles {
            handle.join().unwrap();
        }

        // Each element should have been incremented by 4 (one per writer thread)
        for idx in 0..10usize {
            let cell = vec.get(idx).unwrap();
            let guard = cell.read().unwrap();
            assert_eq!(*guard.get(), idx as i32 + 4);
        }
    }

